#!/bin/bash

# Deploy script to update TicketsPage.jsx on remote server
# This script uses sshpass to SSH into the server, decodes base64 content,
# writes it to the target file, and rebuilds/restarts the frontend container

set -e

SSH_USER="root"
SSH_HOST="143.198.20.6"
SSH_PASSWORD="OdysseY144.-a"
REMOTE_FILE="/opt/carbon-helpdesk/frontend/src/pages/TicketsPage.jsx"
REMOTE_DIR="/opt/carbon-helpdesk"

echo "Starting deployment of TicketsPage.jsx to $SSH_USER@$SSH_HOST..."

# Use sshpass to SSH and execute remote commands
sshpass -p "$SSH_PASSWORD" ssh -o StrictHostKeyChecking=no "$SSH_USER@$SSH_HOST" << 'HEREDOC_END'
set -e

# Create the base64 encoded content using heredoc
read -r -d '' BASE64_CONTENT << 'BASE64_HEREDOC' || true

BASE64_HEREDOC

REMOTE_FILE="/opt/carbon-helpdesk/frontend/src/pages/TicketsPage.jsx"
REMOTE_DIR="/opt/carbon-helpdesk"

# Ensure the directory exists
mkdir -p "$(dirname "$REMOTE_FILE")"

# Decode the base64 content and write it to the file
echo "$BASE64_CONTENT" | base64 -d > "$REMOTE_FILE"
echo "File deployed successfully to $REMOTE_FILE"

# Navigate to the docker-compose directory and rebuild/restart the frontend container
cd "$REMOTE_DIR"
echo "Rebuilding and restarting frontend container..."
docker-compose up -d --build frontend

echo "Frontend container restarted successfully!"
HEREDOC_END

echo "Deployment completed successfully!"
